1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_UNIT_PREMIUM = 25;
5	
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const FIRST_INSURANCE_RATE = 0.1;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_THRESHOLD_YEARS = 2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: COMPONENT_UNIT_PREMIUM,
20	  moonstone: COMPONENT_UNIT_PREMIUM,
21	};
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const DEDUCTIBLE = 100;
33	const CAP_MULTIPLIER = 2;
34	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
35	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	interface Item {
40	  type: string;
41	  material?: string;
42	  enchantment?: number;
43	  cursed?: boolean;
44	}
45	
46	interface QuoteStep {
47	  op: "quote";
48	  items: Item[];
49	}
50	
51	interface Damage {
52	  itemType: string;
53	  amount: number;
54	}
55	
56	interface ClaimStep {
57	  op: "claim";
58	  policy: number;
59	  incident: { cause?: string; damages: Damage[] };
60	}
61	
62	type Step = QuoteStep | ClaimStep;
63	
64	interface Scenario {
65	  customer: { yearsWithMHPCO: number };
66	  steps: Step[];
67	}
68	
69	interface PolicyState {
70	  items: Item[];
71	  insuranceSum: number;
72	  cap: number;
73	  remainingCap: number;
74	}
75	
76	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
77	const isMainItem = (item: Item): boolean => !isComponent(item);
78	
79	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
80	
81	const countsByType = (items: Item[]): Map<string, number> =>
82	  items.reduce((counts, item) => {
83	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
84	    return counts;
85	  }, new Map<string, number>());
86	
87	const componentGroupPremium = (count: number): number =>
88	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
89	
90	const sumComponentPremiums = (components: Item[]): number =>
91	  Array.from(countsByType(components).values()).reduce(
92	    (total, count) => total + componentGroupPremium(count),
93	    0,
94	  );
95	
96	const sumMainItemPremiums = (mainItems: Item[]): number =>
97	  mainItems.reduce((total, item) => total + basePremiumFor(item), 0);
98	
99	const policyBasePremium = (items: Item[]): number =>
100	  sumMainItemPremiums(items.filter(isMainItem)) +
101	  sumComponentPremiums(items.filter(isComponent));
102	
103	const itemModifierSurcharge = (item: Item): number => {
104	  if (isComponent(item)) return 0;
105	  const base = basePremiumFor(item);
106	  let surcharge = 0;
107	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
108	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_RATE;
109	  return surcharge;
110	};
111	
112	const sumItemModifiers = (items: Item[]): number =>
113	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
114	
115	interface CustomerContext {
116	  yearsWithMHPCO: number;
117	  isFollowUpContract: boolean;
118	}
119	
120	const policyModifierAmount = (policyBase: number, ctx: CustomerContext): number => {
121	  let amount = policyBase * FIRST_INSURANCE_RATE;
122	  if (ctx.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) amount -= policyBase * LOYALTY_DISCOUNT_RATE;
123	  if (ctx.isFollowUpContract) amount -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
124	  return amount;
125	};
126	
127	const computeQuote = (step: QuoteStep, ctx: CustomerContext) => {
128	  const policyBase = policyBasePremium(step.items);
129	  const itemSurcharges = sumItemModifiers(step.items);
130	  const policyMods = policyModifierAmount(policyBase, ctx);
131	  const premium = policyBase + itemSurcharges + policyMods + PROCESSING_FEE;
132	  return { premium: Math.ceil(premium) };
133	};
134	
135	const insuranceSumOf = (items: Item[]): number =>
136	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
137	
138	const createPolicy = (items: Item[]): PolicyState => {
139	  const insuranceSum = insuranceSumOf(items);
140	  const cap = insuranceSum * CAP_MULTIPLIER;
141	  return { items, insuranceSum, cap, remainingCap: cap };
142	};
143	
144	const reimbursedAmount = (damage: Damage, item: Item | undefined): number => {
145	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
146	    return damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE;
147	  }
148	  return damage.amount;
149	};
150	
151	const damagePayout = (damage: Damage, item: Item | undefined): number =>
152	  Math.max(0, reimbursedAmount(damage, item) - DEDUCTIBLE);
153	
154	const findItem = (items: Item[], itemType: string): Item | undefined =>
155	  items.find((i) => i.type === itemType);
156	
157	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
158	  damages.reduce((total, damage) => total + damagePayout(damage, findItem(items, damage.itemType)), 0);
159	
160	const processClaim = (step: ClaimStep, policy: PolicyState) => {
161	  const uncappedPayout = sumDamagePayouts(step.incident.damages, policy.items);
162	  const payout = Math.min(uncappedPayout, policy.remainingCap);
163	  policy.remainingCap -= payout;
164	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
165	};
166	
167	interface ScenarioState {
168	  policies: PolicyState[];
169	  quoteCount: number;
170	  yearsWithMHPCO: number;
171	}
172	
173	const handleQuoteStep = (step: QuoteStep, state: ScenarioState) => {
174	  const ctx: CustomerContext = {
175	    yearsWithMHPCO: state.yearsWithMHPCO,
176	    isFollowUpContract: state.quoteCount > 0,
177	  };
178	  state.quoteCount += 1;
179	  state.policies.push(createPolicy(step.items));
180	  return computeQuote(step, ctx);
181	};
182	
183	const handleClaimStep = (step: ClaimStep, state: ScenarioState) =>
184	  processClaim(step, state.policies[step.policy]);
185	
186	export const runScenario = (input: unknown): unknown => {
187	  const scenario = input as Scenario;
188	  const state: ScenarioState = {
189	    policies: [],
190	    quoteCount: 0,
191	    yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
192	  };
193	  const results = scenario.steps.map((step) =>
194	    step.op === "quote" ? handleQuoteStep(step, state) : handleClaimStep(step, state),
195	  );
196	  return { results };
197	};
